
"use client";

import { useState, useTransition, useEffect } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { useToast } from "@/hooks/use-toast";
import { Trash2, Edit, Loader2 } from 'lucide-react';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { deleteVendor, type Vendor } from '@/ai/flows/vendor-flow';

interface VendorListCardProps {
    initialVendors: Vendor[];
}

export function VendorListCard({ initialVendors }: VendorListCardProps) {
    const { toast } = useToast();
    const router = useRouter();
    const [vendors, setVendors] = useState<Vendor[]>(initialVendors);
    const [isPending, startTransition] = useTransition();

    // If the initialVendors prop changes (e.g., after a server refresh), update the state
    useEffect(() => {
        setVendors(initialVendors.filter(v => v.isActive));
    }, [initialVendors]);


    const handleDeleteVendor = (vendorId: string, vendorName: string) => {
      startTransition(async () => {
        try {
          await deleteVendor(vendorId);
          toast({
            title: "店家已刪除",
            description: `${vendorName} 及其所有菜單都已從資料庫移除。`,
          });
          // Refresh the page to get new data from the server
          router.refresh();
        } catch (error) {
          console.error("刪除店家失敗:", error);
          toast({
            variant: "destructive",
            title: "刪除店家失敗",
            description: error instanceof Error ? error.message : "無法刪除店家資料。",
          });
        }
      });
    };

    return (
        <section>
            <Card>
                <CardHeader>
                    <CardTitle>店家列表</CardTitle>
                    <CardDescription>管理現有的店家及菜單。</CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                    {vendors.filter(v => v.isActive).length > 0 ? (
                        vendors.filter(v => v.isActive).map(vendor => (
                            <Card key={vendor.vendorId} className="p-4 flex justify-between items-center">
                                <div>
                                    <p className="font-semibold">{vendor.vendorName}</p>
                                    <p className="text-sm text-muted-foreground">{vendor.description}</p>
                                </div>
                                <div className="flex items-center gap-2">
                                    <Link href={`/admin/menu/${vendor.vendorId}?name=${encodeURIComponent(vendor.vendorName)}`} legacyBehavior>
                                        <a aria-label={`編輯 ${vendor.vendorName} 菜單`} className="inline-flex items-center justify-center">
                                            <Button variant="ghost" size="icon" disabled={isPending}>
                                                <Edit className="h-4 w-4 text-blue-600" />
                                            </Button>
                                        </a>
                                    </Link>
                                    <AlertDialog>
                                        <AlertDialogTrigger asChild>
                                            <Button variant="ghost" size="icon" aria-label={`刪除店家 ${vendor.vendorName}`} disabled={isPending}>
                                                <Trash2 className="h-4 w-4 text-destructive" />
                                            </Button>
                                        </AlertDialogTrigger>
                                        <AlertDialogContent>
                                            <AlertDialogHeader>
                                                <AlertDialogTitle>確定要永久刪除店家嗎？</AlertDialogTitle>
                                                <AlertDialogDescription>
                                                    此動作將會永久刪除「{vendor.vendorName}」及其所有的菜單和選項資料，這個操作無法復原。
                                                </AlertDialogDescription>
                                            </AlertDialogHeader>
                                            <AlertDialogFooter>
                                                <AlertDialogCancel>取消</AlertDialogCancel>
                                                <AlertDialogAction variant="destructive" onClick={() => handleDeleteVendor(vendor.vendorId, vendor.vendorName)} disabled={isPending}>確定刪除</AlertDialogAction>
                                            </AlertDialogFooter>
                                        </AlertDialogContent>
                                    </AlertDialog>
                                </div>
                            </Card>
                        ))
                    ) : (
                      <p className="text-sm text-center text-muted-foreground py-4">您的美食地圖還是空的，快來插上第一支旗幟吧！</p>
                    )}
                </CardContent>
            </Card>
        </section>
    );
}
